use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

# Function to extract text from a PDF file
sub extract_text_from_pdf {
    my ($file_path) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($file_path);

    # Create a text extraction object
    my $text = PDF::Text::Simple->new($pdf);

    # Initialize a variable to store extracted text
    my $extracted_text = '';

    # Extract text from each page
    for my $page (1 .. $pdf->pages) {
        $extracted_text .= $text->text($page) . "\n";
    }

    return $extracted_text;
}

# Main script
my $pdf_file = 'example.pdf';  # Replace with your PDF file path
my $extracted_text = extract_text_from_pdf($pdf_file);

# Print the extracted text
print $extracted_text;
